module top_module(clk, reset, data_in, enable, data_out);input clk, reset, enable;
    input [31:0] data_in;
    output [31:0] data_out;
    reg [31:0] data_reg;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_reg <= 0;
        end else if (enable) begin
            data_reg <= data_in;
        end
    end

    assign data_out = data_reg;
endmodule
